/**
 * Phase 32.2-Fix — configuration for the inventory item-type Add/Edit forms.
 *
 * The forms are type-driven: asset.type selects a variant set (inventory_subtype)
 * and a Section-2 field group. Type-specific attributes are stored in
 * Asset.metadata (JSONB) with metadata_schema_version = 1 — no new per-type
 * tables are introduced in this phase.
 *
 * Final stored barcodes are ALWAYS generated by the backend
 * (barcode-identity.service). The form only chooses taxonomy (inventory code /
 * item code / karat) and renders a read-only preview.
 */

import type { AssetType } from "@/lib/types";

export const INVENTORY_METADATA_SCHEMA_VERSION = 1;

// Documented frontend fallback for the owner-approved provisional Watch type,
// used only when the company-scoped barcode settings API is unavailable
// (e.g. local/demo mode). The database rows remain the source of truth.
export const WATCH_FALLBACK_CODES = Object.freeze({
  inventoryCode: "WT",
  itemCode: "WCH",
  karatCode: "00",
});

export interface InventoryVariant {
  /** Stored in Asset.inventory_subtype. */
  value: string;
  label: string;
  labelAr: string;
  /** Loose stones/pearls — backend requires a configured default karat code. */
  loose?: boolean;
  /** 24K / gold bar variant. */
  bar?: boolean;
}

export interface InventoryTypeConfig {
  type: AssetType;
  label: string;
  labelAr: string;
  /** Default inventory code (settings override this when available). */
  defaultInventoryCode: string;
  /** Whether a karat value is normally required for this family. */
  karatRequired: boolean;
  /** Whether a positive weight is required (gold-weight). */
  weightRequired: boolean;
  /** Section-2 heading. */
  section2Title: string;
  section2TitleAr: string;
  variants: InventoryVariant[];
}

