export function getTypeConfig(type: AssetType): InventoryTypeConfig {
  return INVENTORY_TYPE_CONFIGS.find((config) => config.type === type) ?? INVENTORY_TYPE_CONFIGS[0];
}

export function isLooseVariant(config: InventoryTypeConfig, variantValue: string): boolean {
  return Boolean(config.variants.find((variant) => variant.value === variantValue)?.loose);
}
